import React, { useState, useEffect } from 'react';
import { useParams } from 'react-router-dom';
import axios from 'axios';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  Legend,
  ResponsiveContainer,
  AreaChart,
  Area
} from 'recharts';
import toast from 'react-hot-toast';

const API_URL = 'http://localhost:5000/api';

function ProductDetail() {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    fetchProductDetails();
  }, [id]);

  const fetchProductDetails = async () => {
    setLoading(true);
    setError(null);
    
    try {
      const response = await axios.get(`${API_URL}/products/${id}`, {
        withCredentials: true
      });
      
      console.log('Product data received:', response.data);
      setProduct(response.data);
      
    } catch (error) {
      console.error('Error fetching product details:', error);
      setError(error.response?.data?.error || 'Failed to load product details');
      toast.error('Failed to load product details');
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div style={{ textAlign: 'center', padding: '50px' }}>
        <div style={{ fontSize: '1.2rem' }}>Loading product details...</div>
      </div>
    );
  }

  if (error) {
    return (
      <div style={{ textAlign: 'center', padding: '50px' }}>
        <div style={{ color: '#f56565', fontSize: '1.2rem', marginBottom: '20px' }}>
          Error: {error}
        </div>
        <button onClick={() => window.location.href = '/dashboard'}>
          Back to Dashboard
        </button>
      </div>
    );
  }

  if (!product) {
    return (
      <div style={{ textAlign: 'center', padding: '50px' }}>
        <div>Product not found</div>
        <button onClick={() => window.location.href = '/dashboard'}>
          Back to Dashboard
        </button>
      </div>
    );
  }

  const getDecisionColor = (decision) => {
    switch(decision) {
      case 'BUY_NOW': return '#48bb78';
      case 'BUY_SOON': return '#ecc94b';
      default: return '#f56565';
    }
  };

  const getDecisionText = (decision) => {
    switch(decision) {
      case 'BUY_NOW': return '🟢 BUY NOW';
      case 'BUY_SOON': return '🟡 BUY BEFORE INCREASE';
      default: return '🔴 WAIT';
    }
  };

  // Safely format price history data
  const priceHistoryData = product.price_history && Array.isArray(product.price_history) 
    ? product.price_history.map(item => ({
        date: new Date(item.date).toLocaleDateString(),
        price: item.price
      }))
    : [];

  // Safely format prediction data
  const predictionData = product.predictions && product.predictions.dates && product.predictions.prices
    ? product.predictions.dates.map((date, idx) => ({
        date: new Date(date).toLocaleDateString(),
        predicted: product.predictions.prices[idx],
        lower: product.predictions.lower_bound ? product.predictions.lower_bound[idx] : product.predictions.prices[idx] * 0.9,
        upper: product.predictions.upper_bound ? product.predictions.upper_bound[idx] : product.predictions.prices[idx] * 1.1
      }))
    : [];

  return (
    <div style={{ maxWidth: '1200px', margin: '0 auto', padding: '20px' }}>
      {/* Header */}
      <div style={{ marginBottom: '30px' }}>
        <button 
          onClick={() => window.location.href = '/dashboard'}
          style={{ 
            background: 'transparent', 
            color: 'var(--text-primary)',
            padding: '8px 16px',
            marginBottom: '20px'
          }}
        >
          ← Back to Dashboard
        </button>
        <h1 style={{ marginBottom: '10px' }}>{product.name || 'Product'}</h1>
        {product.url && (
          <a 
            href={product.url} 
            target="_blank" 
            rel="noopener noreferrer" 
            style={{ color: 'var(--text-secondary)' }}
          >
            View on Store →
          </a>
        )}
      </div>

      {/* Recommendation Card */}
      <div style={{
        background: 'var(--bg-secondary)',
        borderRadius: '12px',
        padding: '30px',
        marginBottom: '30px',
        textAlign: 'center',
        borderLeft: `4px solid ${getDecisionColor(product.recommendation?.decision || 'WAIT')}`,
        boxShadow: 'var(--card-shadow)'
      }}>
        <div style={{ fontSize: '1.2rem', marginBottom: '10px', color: 'var(--text-secondary)' }}>
          AI Recommendation
        </div>
        <div style={{
          fontSize: '2rem',
          fontWeight: 'bold',
          color: getDecisionColor(product.recommendation?.decision || 'WAIT'),
          marginBottom: '15px'
        }}>
          {getDecisionText(product.recommendation?.decision || 'WAIT')}
        </div>
        <div style={{ marginBottom: '10px', fontSize: '1.1rem' }}>
          Confidence Score: <strong>{product.recommendation?.confidence || 0}%</strong>
        </div>
        <div style={{ color: 'var(--text-secondary)', maxWidth: '600px', margin: '0 auto' }}>
          {product.recommendation?.reasoning || 'Analyzing price patterns...'}
        </div>
      </div>

      {/* Price Info Cards */}
      <div style={{
        display: 'grid',
        gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
        gap: '20px',
        marginBottom: '30px'
      }}>
        <div className="chart-container" style={{ background: 'var(--bg-secondary)', borderRadius: '12px', padding: '20px' }}>
          <h3 style={{ marginBottom: '15px' }}>Current Price</h3>
          <div style={{ fontSize: '2.5rem', fontWeight: 'bold', color: '#48bb78' }}>
            ${product.current_price || '0.00'}
          </div>
          {product.original_price && product.original_price > 0 && (
            <div style={{ textDecoration: 'line-through', color: 'var(--text-secondary)', marginTop: '5px' }}>
              Original: ${product.original_price}
            </div>
          )}
        </div>

        <div className="chart-container" style={{ background: 'var(--bg-secondary)', borderRadius: '12px', padding: '20px' }}>
          <h3 style={{ marginBottom: '15px' }}>Discount Analysis</h3>
          <div style={{ fontSize: '1.2rem', marginBottom: '10px' }}>
            {product.discount_info?.is_genuine ? '✅ Genuine Discount' : '⚠️ Check Discount'}
          </div>
          {product.discount_info?.discount_percentage > 0 && (
            <div style={{ fontSize: '1.5rem', fontWeight: 'bold', color: '#48bb78' }}>
              {product.discount_info.discount_percentage}% OFF
            </div>
          )}
          <div style={{ fontSize: '0.9rem', marginTop: '10px', color: 'var(--text-secondary)' }}>
            {product.discount_info?.message || 'No discount information available'}
          </div>
        </div>

        <div className="chart-container" style={{ background: 'var(--bg-secondary)', borderRadius: '12px', padding: '20px' }}>
          <h3 style={{ marginBottom: '15px' }}>Seller Analysis</h3>
          <div style={{ marginBottom: '10px' }}>
            {product.seller_insights?.message || 'Analyzing seller patterns...'}
          </div>
          {product.seller_insights?.next_move_prediction && (
            <div style={{ fontSize: '0.9rem', marginTop: '10px' }}>
              Predicted next move: <strong>{product.seller_insights.next_move_prediction}</strong>
            </div>
          )}
        </div>
      </div>

      {/* Price History Chart */}
      {priceHistoryData.length > 0 && (
        <div className="chart-container" style={{ 
          background: 'var(--bg-secondary)', 
          borderRadius: '12px', 
          padding: '20px',
          marginBottom: '30px'
        }}>
          <h3 style={{ marginBottom: '20px' }}>Price History (30 Days)</h3>
          <ResponsiveContainer width="100%" height={400}>
            <LineChart data={priceHistoryData}>
              <CartesianGrid strokeDasharray="3 3" stroke="var(--border-color)" />
              <XAxis dataKey="date" stroke="var(--text-secondary)" />
              <YAxis stroke="var(--text-secondary)" />
              <Tooltip 
                contentStyle={{ 
                  background: 'var(--bg-primary)', 
                  border: '1px solid var(--border-color)',
                  color: 'var(--text-primary)'
                }}
              />
              <Legend />
              <Line 
                type="monotone" 
                dataKey="price" 
                stroke="#48bb78" 
                strokeWidth={2}
                name="Actual Price" 
                dot={false}
              />
            </LineChart>
          </ResponsiveContainer>
        </div>
      )}

      {/* Price Prediction Chart */}
      {predictionData.length > 0 && (
        <div className="chart-container" style={{ 
          background: 'var(--bg-secondary)', 
          borderRadius: '12px', 
          padding: '20px'
        }}>
          <h3 style={{ marginBottom: '20px' }}>Price Prediction (Next 7 Days)</h3>
          <ResponsiveContainer width="100%" height={400}>
            <AreaChart data={predictionData}>
              <CartesianGrid strokeDasharray="3 3" stroke="var(--border-color)" />
              <XAxis dataKey="date" stroke="var(--text-secondary)" />
              <YAxis stroke="var(--text-secondary)" />
              <Tooltip 
                contentStyle={{ 
                  background: 'var(--bg-primary)', 
                  border: '1px solid var(--border-color)',
                  color: 'var(--text-primary)'
                }}
              />
              <Legend />
              <Area 
                type="monotone" 
                dataKey="predicted" 
                stroke="#ecc94b" 
                fill="#ecc94b" 
                fillOpacity={0.3}
                name="Predicted Price" 
              />
            </AreaChart>
          </ResponsiveContainer>
          {product.predictions?.trend && (
            <div style={{ marginTop: '15px', textAlign: 'center', color: 'var(--text-secondary)' }}>
              Trend: <strong>{product.predictions.trend}</strong>
            </div>
          )}
        </div>
      )}

      {/* Debug Info (only visible in development) */}
      {process.env.NODE_ENV === 'development' && (
        <div style={{ 
          marginTop: '30px', 
          padding: '15px', 
          background: 'var(--bg-secondary)',
          borderRadius: '8px',
          fontSize: '12px'
        }}>
          <details>
            <summary>Debug Info</summary>
            <pre>{JSON.stringify(product, null, 2)}</pre>
          </details>
        </div>
      )}
    </div>
  );
}

export default ProductDetail;
